import '/Users/zcy/Desktop/pc-virtual-table-front-release-3.0.1/pages/pages/reference/watch/code/immediately.tsx?watch=parent';import React, { useState } from 'react';
import VirtualTable from 'react-tablex';

const columns = [
  {
    label: '序号',
    fieldkey: 'index',
    width: 80,
    custom: VirtualTable.VirtualNo,
  },
  {
    label: '是否开启',
    fieldkey: 'type',
    require: true,
    rules: [{ required: true, message: '必填' }],
    type: 'Radio',
    initialValue: true,
    options: [
      { label: '是', value: true },
      { label: '否', value: false },
    ],
  },
  {
    label: '价格',
    fieldkey: 'price',
    rules: [{ required: true, message: '必填' }],
    type: 'InputNumber',
    attrs: {
      min: 0,
      max: 10,
    },
    fieldShow: false,
    watch: [{
      handle(value, { updateSelfConfig }) {
        updateSelfConfig({
          fieldShow: value,
        });
      },
      deps: ['type'],
      immediately: true,
    }],
  },
];

const Demo = () => {
  const [dateSource, setDataSource] = useState([]);

  const onChange = (value) => {
    setDataSource(value);
  };

  return (
    <VirtualTable columns={columns} value={dateSource} onChange={onChange} />
  );
};

export default Demo;
